import { d3_event } from '../../../../core/d3-constants';
import { hideTooltip } from '../../../../behaviours/visual-effects/legend/size-slider/hide-tooltip';
import { fullEncode } from '../../../legend-api';

function hideBrushTooltip() {
    d3_event().stopImmediatePropagation();

    let manager = this,
        { chart } = manager,
        { encode, view } = manager.options.legendInstance.meta,
        behaviourName = `LEGEND_${fullEncode(encode).toUpperCase()}_${view.toUpperCase()}_BRUSH`,
        brushBehaviour = chart.behaviouralEvents.eventManager.behaviours[behaviourName];

    if (brushBehaviour) {
        hideTooltip(brushBehaviour, null, null, null, true);
    }
}

export { hideBrushTooltip };
